def setup_logging(
    log_dir="/var/log/application",
    app_name="application",
    max_bytes=10 * 1024 * 1024,  # 10 MB
    backup_count=5,
    log_level=logging.INFO,
):
    """
    Configure production logging with file rotation, proper permissions,
    and secure file handling.
    """

    # Create log directory with restrictive permissions if it doesn't exist
    if not os.path.exists(log_dir):
        os.makedirs(log_dir, mode=0o750, exist_ok=True)
    else:
        # Ensure existing directory has correct permissions
        os.chmod(log_dir, 0o750)

    # Validate log directory path to prevent path traversal
    log_dir_real = os.path.realpath(log_dir)
    if not log_dir_real.startswith("/var/log/"):
        raise ValueError(
            f"Log directory must be under /var/log/. Got: {log_dir_real}"
        )

    # Define log file paths
    app_log_file = os.path.join(log_dir_real, f"{app_name}.log")
    error_log_file = os.path.join(log_dir_real, f"{app_name}_error.log")
    audit_log_file = os.path.join(log_dir_real, f"{app_name}_audit.log")

    # Validate filenames don't contain path traversal
    for log_file in [app_log_file, error_log_file, audit_log_file]:
        real_path = os.path.realpath(log_file)
        if not real_path.startswith(log_dir_real):
            raise ValueError(
                f"Log file path traversal detected: {log_file}"
            )

    # Define secure log format (avoid logging sensitive data)
    standard_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S%z",
    )

    error_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(process)d:%(thread)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S%z",
    )

    audit_formatter = logging.Formatter(
        fmt="%(asctime)s | AUDIT | %(name)s | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S%z",
    )

    # Get root logger
    root_logger = logging.getLogger()
    root_logger.setLevel(log_level)

    # Clear any existing handlers
    root_logger.handlers.clear()

    # --- Application Log Handler (rotating) ---
    app_handler = logging.handlers.RotatingFileHandler(
        filename=app_log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    app_handler.setLevel(log_level)
    app_handler.setFormatter(standard_formatter)
    _secure_log_file(app_log_file)

    # --- Error Log Handler (rotating) ---
    error_handler = logging.handlers.RotatingFileHandler(
        filename=error_log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(error_formatter)
    _secure_log_file(error_log_file)

    # --- Audit Log Handler (time-based rotation) ---
    audit_handler = logging.handlers.TimedRotatingFileHandler(
        filename=audit_log_file,
        when="midnight",
        interval=1,
        backupCount=30,  # Keep 30 days of audit logs
        encoding="utf-8",
        utc=True,
    )
    audit_handler.setLevel(logging.INFO)
    audit_handler.setFormatter(audit_formatter)
    _secure_log_file(audit_log_file)

    # Add filter to audit handler so it only processes audit logger messages
    audit_handler.addFilter(logging.Filter(name="audit"))

    # Add handlers to root logger
    root_logger.addHandler(app_handler)
    root_logger.addHandler(error_handler)

    # Set up dedicated audit logger
    audit_logger = logging.getLogger("audit")
    audit_logger.addHandler(audit_handler)
    audit_logger.setLevel(logging.INFO)
    # Prevent audit messages from propagating to root logger's handlers
    audit_logger.propagate = False

    # Add a sanitizing filter to all handlers
    sanitize_filter = SensitiveDataFilter()
    app_handler.addFilter(sanitize_filter)
    error_handler.addFilter(sanitize_filter)

    root_logger.info("Logging infrastructure initialized successfully.")

    return root_logger


def _secure_log_file(filepath):
    """Set restrictive file permissions on log files (owner read/write only)."""
    if os.path.exists(filepath):
        # rw for owner only, no permissions for group/others
        os.chmod(filepath, stat.S_IRUSR | stat.S_IWUSR)


class SensitiveDataFilter(logging.Filter):
    """
    Filter that redacts potentially sensitive data from log messages.
    Prevents accidental logging of passwords, tokens, SSNs, credit cards, etc.
    """

    import re

    # Patterns for common sensitive data
    SENSITIVE_PATTERNS = [
        # Credit card numbers (basic pattern)
        (re.compile(r'\b(?:\d{4}[-\s]?){3}\d{4}\b'), '[REDACTED_CC]'),
        # SSN pattern
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '[REDACTED_SSN]'),
        # Email addresses (partial redaction)
        (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), '[REDACTED_EMAIL]'),
        # Common secret/password/token key-value patterns
        (re.compile(
            r'(?i)(password|passwd|pwd|secret|token|api_key|apikey|access_key|private_key|authorization)\s*[=:]\s*\S+'),
         r'\1=[REDACTED]'),
        # Bearer tokens
        (re.compile(r'(?i)Bearer\s+[A-Za-z0-9\-._~+/]+=*'), 'Bearer [REDACTED]'),
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            record.msg = self._sanitize(record.msg)
        if record.args:
            if isinstance(record.args, dict):
                record.args = {
                    k: self._sanitize(str(v)) if isinstance(v, str) else v
                    for k, v in record.args.items()
                }
            elif isinstance(record.args, tuple):
                record.args = tuple(
                    self._sanitize(str(a)) if isinstance(a, str) else a
                    for a in record.args
                )
        return True

    def _sanitize(self, message):
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            message = pattern.sub(replacement, message)
        return message


def get_audit_logger():
    """Get the dedicated audit logger for security/compliance events."""
    return logging.getLogger("audit")


def get_logger(name):
    """Get a named logger for a specific module/component."""
    return logging.getLogger(name)


